     1→import React, { useState, useEffect, useCallback } from 'react';
     2→import { useSearchParams } from 'react-router-dom';
     3→import { motion, AnimatePresence } from 'framer-motion';
     4→import { format } from 'date-fns';
     5→import {
     6→  Settings as SettingsIcon,
     7→  Clock,
     8→  CheckSquare,
     9→  FileText,
    10→  HardDrive,
    11→  Bot,
    12→  Sliders,
    13→  ChevronRight,
    14→  FolderTree,
    15→} from 'lucide-react';
    16→import {
    17→  exportBrainFile,
    18→  importBrainFile,
    19→  validateBrainFile,
    20→  formatFileSize,
    21→} from '../services/brainBackup';
    22→import {
    23→  loadPreferences,
    24→  getBackupHistory,
    25→  shouldShowBackupReminder,
    26→  getTimeSinceLastBackup,
    27→  addHistoryEntry,
    28→  type BackupPreferences,
    29→  type BackupHistoryEntry,
    30→} from '../services/backupPreferences';
    31→import { PageContent } from '../components/PageContent';
    32→import { indexedDBService } from '../services/indexedDB';
    33→import { exportToICS, importFromICS, downloadICS, readICSFile } from '../services/icsImportExport';
    34→import { requestNotificationPermission } from '../services/eventReminders';
    35→import { useCalendarStore } from '../stores/useCalendarStore';
    36→import { BackupSettings } from '../components/BackupSettings';
    37→import { PresetManager } from '../components/PresetManager';
    38→import { logger } from '../services/logger';
    39→import { ImportData } from '../widgets/Settings/ImportData';
    40→import { DailyNotesSettings } from '../widgets/Settings/DailyNotesSettings';
    41→import { TemplateSettings } from '../widgets/Settings/TemplateSettings';
    42→import { ExportSettings } from '../widgets/Settings/ExportSettings';
    43→import { AboutSettings } from '../widgets/Settings/AboutSettings';
    44→import { AccountSettings } from '../widgets/Settings/AccountSettings';
    45→import { SiteWideSettings } from '../widgets/Settings/SiteWideSettings';
    46→import { TaskManagementSettings } from '../widgets/Settings/TaskManagementSettings';
    47→import { QuickActionsSection } from '../widgets/Settings/QuickActionsSection';
    48→import { AutoSaveSettings } from '../widgets/Settings/AutoSaveSettings';
    49→import { BackupHistorySection } from '../widgets/Settings/BackupHistorySection';
    50→import { BackupOptionsSection } from '../widgets/Settings/BackupOptionsSection';
    51→import { TimeTrackingPanelSettings } from '../widgets/Settings/TimeTrackingPanelSettings';
    52→import CustomFieldsSettings from '../components/CustomFieldsSettings';
    53→import MemberSettings from '../components/MemberSettings';
    54→import { AutoTrackingSettings } from '../components/AutoTrackingSettings';
    55→import { AITerminalSettingsSection } from '../widgets/Settings/AITerminalSettingsSection';
    56→import { StorageInfoSection } from '../widgets/Settings/StorageInfoSection';
    57→import { DashboardSettingsSection } from '../widgets/Settings/DashboardSettingsSection';
    58→import { CalendarNotificationsSection } from '../widgets/Settings/CalendarNotificationsSection';
    59→import { CalendarImportExportSection } from '../widgets/Settings/CalendarImportExportSection';
    60→import { WidgetSettingsSection } from '../widgets/Settings/WidgetSettingsSection';
    61→import { ProjectSettings } from '../widgets/Settings/ProjectSettings';
    62→
    63→const log = logger.module('Settings');
    64→
    65→/**
    66→ * Settings Tab Configuration
    67→ */
    68→const SETTINGS_TABS = [
    69→  { id: 'general', label: 'General', icon: SettingsIcon },
    70→  { id: 'projects', label: 'Projects', icon: FolderTree },
    71→  { id: 'time', label: 'Time Tracking', icon: Clock },
    72→  { id: 'tasks', label: 'Tasks', icon: CheckSquare },
    73→  { id: 'notes', label: 'Notes & Calendar', icon: FileText },
    74→  { id: 'backup', label: 'Backup & Data', icon: HardDrive },
    75→  { id: 'ai', label: 'AI Terminal', icon: Bot },
    76→  { id: 'advanced', label: 'Advanced', icon: Sliders },
    77→] as const;
    78→
    79→type SettingsTabId = (typeof SETTINGS_TABS)[number]['id'];
    80→
    81→/**
    82→ * Settings Page - Modern Tab-Based Layout
    83→ * Local-first privacy with comprehensive settings management
    84→ */
    85→export const Settings: React.FC = () => {
    86→  const [searchParams, setSearchParams] = useSearchParams();
    87→  const currentTab = (searchParams.get('tab') as SettingsTabId) || 'general';
    88→
    89→  // State management
    90→  const [isExporting, setIsExporting] = useState(false);
    91→  const [isImporting, setIsImporting] = useState(false);
    92→  const [message, setMessage] = useState<{ type: 'success' | 'error' | 'info' | 'warning'; text: string } | null>(null);
    93→
    94→  // Preferences
    95→  const [preferences, setPreferences] = useState<BackupPreferences | null>(null);
    96→  const [backupHistory, setBackupHistory] = useState<BackupHistoryEntry[]>([]);
    97→  const [timeSinceLastBackup, setTimeSinceLastBackup] = useState<string | null>(null);
    98→  const [backupReminder, setBackupReminder] = useState<{ show: boolean; daysSinceLastBackup?: number; message?: string } | null>(null);
    99→
   100→  // Storage Info
   101→  const [storageInfo, setStorageInfo] = useState<{
   102→    usageFormatted: string;
   103→    availableFormatted: string;
   104→    quotaFormatted: string;
   105→    percentUsed: number;
   106→  } | null>(null);
   107→
   108→  // New Browser Warning
   109→  const [showNewBrowserWarning, setShowNewBrowserWarning] = useState(false);
   110→
   111→  // Dashboard Settings modal
   112→  const [showPresetManager, setShowPresetManager] = useState(false);
   113→
   114→  // Calendar Import/Export
   115→  const [isExportingCalendar, setIsExportingCalendar] = useState(false);
   116→  const [isImportingCalendar, setIsImportingCalendar] = useState(false);
   117→  const events = useCalendarStore((s) => s.events);
   118→  const importEvents = useCalendarStore((s) => s.importEvents);
   119→
   120→  // Notification Permission
   121→  const [notificationPermission, setNotificationPermission] = useState<NotificationPermission>('default');
   122→  const [requestingPermission, setRequestingPermission] = useState(false);
   123→
   124→  // Check notification permission on mount
   125→  useEffect(() => {
   126→    if ('Notification' in window) {
   127→      setNotificationPermission(Notification.permission);
   128→    }
   129→  }, []);
   130→
   131→  const loadAllData = useCallback(async () => {
   132→    // Load preferences
   133→    const prefs = await loadPreferences();
   134→    setPreferences(prefs);
   135→
   136→    // Load backup history
   137→    const history = await getBackupHistory();
   138→    setBackupHistory(history);
   139→
   140→    // Get time since last backup
   141→    const timeSince = await getTimeSinceLastBackup();
   142→    setTimeSinceLastBackup(timeSince);
   143→
   144→    // Check backup reminder
   145→    const reminder = await shouldShowBackupReminder();
   146→    setBackupReminder(reminder);
   147→
   148→    // Load storage quota info
   149→    try {
   150→      const quota = await indexedDBService.getQuota();
   151→      setStorageInfo(quota);
   152→
   153→      // Check if this is a new browser (no data in IndexedDB)
   154→      const keys = await indexedDBService.getAllKeys();
   155→      const hasAnyData = keys.length > 0;
   156→
   157→      // Show new browser warning if no data AND not dismissed
   158→      const dismissed = localStorage.getItem('new-browser-warning-dismissed');
   159→      if (!hasAnyData && !dismissed) {
   160→        setShowNewBrowserWarning(true);
   161→      }
   162→    } catch (error) {
   163→      log.error('Failed to load storage info', { error });
   164→    }
   165→  }, []);
   166→
   167→  // Load data on mount
   168→  useEffect(() => {
   169→    document.title = 'Settings - Neuman Brain';
   170→    loadAllData();
   171→  }, [loadAllData]);
   172→
   173→  // Handle tab change
   174→  const setTab = (tabId: SettingsTabId) => {
   175→    setSearchParams({ tab: tabId });
   176→  };
   177→
   178→  // Export handler
   179→  const handleExport = async (compressed: boolean = true) => {
   180→    try {
   181→      setIsExporting(true);
   182→      setMessage(null);
   183→
   184→      const result = await exportBrainFile({ compressed, prettyPrint: !compressed });
   185→
   186→      // Add to history
   187→      await addHistoryEntry({
   188→        filename: result.filename,
   189→        size: result.size,
   190→        compressed: result.compressed,
   191→        type: 'manual',
   192→        status: 'success',
   193→      });
   194→
   195→      await loadAllData(); // Refresh
   196→
   197→      const sizeInfo = formatFileSize(result.size);
   198→      const compressionNote = compressed ? ' (compressed)' : '';
   199→      setMessage({
   200→        type: 'success',
   201→        text: `Brain data exported successfully! File size: ${sizeInfo}${compressionNote}`
   202→      });
   203→    } catch (error) {
   204→      setMessage({ type: 'error', text: `Export failed: ${error}` });
   205→    } finally {
   206→      setIsExporting(false);
   207→    }
   208→  };
   209→
   210→  // Import handler
   211→  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
   212→    const file = event.target.files?.[0];
   213→    if (!file) return;
   214→
   215→    try {
   216→      setIsImporting(true);
   217→      setMessage(null);
   218→
   219→      const validation = await validateBrainFile(file);
   220→      if (!validation.valid) {
   221→        setMessage({ type: 'error', text: validation.message });
   222→        return;
   223→      }
   224→
   225→      if (validation.info) {
   226→        setMessage({
   227→          type: 'info',
   228→          text: `Found ${validation.info.itemCount} items (${validation.info.fileSize}) from ${new Date(validation.info.exportDate).toLocaleString()}. Importing...`,
   229→        });
   230→      }
   231→
   232→      const result = await importBrainFile(file);
   233→      if (result.success) {
   234→        setMessage({ type: 'success', text: result.message });
   235→        setTimeout(() => window.location.reload(), 2000);
   236→      } else {
   237→        setMessage({ type: 'error', text: result.message });
   238→      }
   239→    } catch (error) {
   240→      setMessage({ type: 'error', text: `Import failed: ${error}` });
   241→    } finally {
   242→      setIsImporting(false);
   243→    }
   244→  };
   245→
   246→  // Calendar handlers
   247→  const handleExportCalendar = async () => {
   248→    try {
   249→      setIsExportingCalendar(true);
   250→      setMessage(null);
   251→
   252→      const result = exportToICS(events);
   253→
   254→      if (!result.success || !result.data) {
   255→        setMessage({ type: 'error', text: result.error || 'Export failed' });
   256→        return;
   257→      }
   258→
   259→      downloadICS(result.data, `calendar-${format(new Date(), 'yyyy-MM-dd')}.ics`);
   260→
   261→      const eventCount = Object.values(events).reduce((acc, arr) => acc + arr.length, 0);
   262→      setMessage({
   263→        type: 'success',
   264→        text: `Calendar exported successfully! ${eventCount} events saved to .ics file.`
   265→      });
   266→    } catch (error) {
   267→      setMessage({ type: 'error', text: `Calendar export failed: ${error}` });
   268→    } finally {
   269→      setIsExportingCalendar(false);
   270→    }
   271→  };
   272→
   273→  const handleICSFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
   274→    const file = event.target.files?.[0];
   275→    if (!file) return;
   276→
   277→    try {
   278→      setIsImportingCalendar(true);
   279→      setMessage(null);
   280→
   281→      const icsData = await readICSFile(file);
   282→      const result = importFromICS(icsData);
   283→
   284→      if (!result.success || !result.events) {
   285→        setMessage({ type: 'error', text: result.error || 'Import failed' });
   286→        return;
   287→      }
   288→
   289→      const count = importEvents(result.events);
   290→
   291→      setMessage({
   292→        type: 'success',
   293→        text: `Calendar imported successfully! ${count} events added.`
   294→      });
   295→    } catch (error) {
   296→      setMessage({ type: 'error', text: `Calendar import failed: ${error}` });
   297→    } finally {
   298→      setIsImportingCalendar(false);
   299→      // Reset input value to allow re-importing same file
   300→      event.target.value = '';
   301→    }
   302→  };
   303→
   304→  // Notification permission handler
   305→  const handleRequestNotificationPermission = async () => {
   306→    try {
   307→      setRequestingPermission(true);
   308→      const granted = await requestNotificationPermission();
   309→      setNotificationPermission(granted ? 'granted' : 'denied');
   310→      setMessage({
   311→        type: granted ? 'success' : 'warning',
   312→        text: granted
   313→          ? 'Notifications enabled! You will now receive event reminders.'
   314→          : 'Notification permission denied. You can enable it later in your browser settings.',
   315→      });
   316→    } catch (error) {
   317→      log.error('Failed to request notification permission', { error });
   318→      setMessage({ type: 'error', text: 'Failed to request notification permission' });
   319→    } finally {
   320→      setRequestingPermission(false);
   321→    }
   322→  };
   323→
   324→  if (!preferences) {
   325→    return <div className="p-6">Loading...</div>;
   326→  }
   327→
   328→  return (
   329→    <PageContent page="settings">
   330→      {/* Message Banner */}
   331→      <AnimatePresence>
   332→        {message && (
   333→          <motion.div
   334→            initial={{ opacity: 0, y: -10 }}
   335→            animate={{ opacity: 1, y: 0 }}
   336→            exit={{ opacity: 0, y: -10 }}
   337→            className={`mb-6 p-4 rounded-lg ${
   338→              message.type === 'success'
   339→                ? 'bg-status-success-bg dark:bg-status-success-bg-dark text-status-success-text dark:text-status-success-text-dark border border-status-success-border dark:border-status-success-border-dark'
   340→                : message.type === 'error'
   341→                ? 'bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark border border-status-error-border dark:border-status-error-border-dark'
   342→                : message.type === 'warning'
   343→                ? 'bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark border border-status-warning-border dark:border-status-warning-border-dark'
   344→                : 'bg-status-info-bg dark:bg-status-info-bg-dark text-status-info-text dark:text-status-info-text-dark border border-status-info-border dark:border-status-info-border-dark'
   345→            }`}
   346→          >
   347→            {message.text}
   348→          </motion.div>
   349→        )}
   350→      </AnimatePresence>
   351→
   352→      {/* Backup Reminder Banner */}
   353→      {backupReminder?.show && (
   354→        <motion.div
   355→          initial={{ opacity: 0, y: -10 }}
   356→          animate={{ opacity: 1, y: 0 }}
   357→          className="mb-6 p-4 rounded-lg bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark border border-status-warning-border dark:border-status-warning-border-dark flex items-start gap-3"
   358→        >
   359→          <span className="text-2xl">⚠️</span>
   360→          <div className="flex-1">
   361→            <p className="font-semibold">{backupReminder.message}</p>
   362→            <button
   363→              onClick={() => handleExport(preferences.compressionEnabled)}
   364→              className="mt-2 text-sm underline hover:no-underline"
   365→            >
   366→              Create Backup Now
   367→            </button>
   368→          </div>
   369→        </motion.div>
   370→      )}
   371→
   372→      {/* Main Layout: Sidebar + Content */}
   373→      <div className="flex gap-6">
   374→        {/* Tab Navigation Sidebar */}
   375→        <nav className="w-56 flex-shrink-0 hidden md:block">
   376→          <div className="sticky top-4 space-y-1">
   377→            {SETTINGS_TABS.map((tab) => {
   378→              const Icon = tab.icon;
   379→              const isActive = currentTab === tab.id;
   380→              return (
   381→                <button
   382→                  key={tab.id}
   383→                  onClick={() => setTab(tab.id)}
   384→                  className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-lg text-left transition-all duration-200 ${
   385→                    isActive
   386→                      ? 'bg-accent-magenta/10 dark:bg-accent-cyan/10 text-accent-magenta dark:text-accent-cyan font-medium'
   387→                      : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated hover:text-text-light-primary dark:hover:text-text-dark-primary'
   388→                  }`}
   389→                >
   390→                  <Icon className="w-5 h-5 flex-shrink-0" />
   391→                  <span className="flex-1">{tab.label}</span>
   392→                  {isActive && (
   393→                    <ChevronRight className="w-4 h-4 opacity-50" />
   394→                  )}
   395→                </button>
   396→              );
   397→            })}
   398→          </div>
   399→        </nav>
   400→
   401→        {/* Mobile Tab Selector */}
   402→        <div className="md:hidden mb-4 w-full">
   403→          <select
   404→            value={currentTab}
   405→            onChange={(e) => setTab(e.target.value as SettingsTabId)}
   406→            className="w-full px-4 py-3 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan"
   407→          >
   408→            {SETTINGS_TABS.map((tab) => (
   409→              <option key={tab.id} value={tab.id}>
   410→                {tab.label}
   411→              </option>
   412→            ))}
   413→          </select>
   414→        </div>
   415→
   416→        {/* Content Area */}
   417→        <div className="flex-1 min-w-0">
   418→          <AnimatePresence mode="wait">
   419→            <motion.div
   420→              key={currentTab}
   421→              initial={{ opacity: 0, x: 10 }}
   422→              animate={{ opacity: 1, x: 0 }}
   423→              exit={{ opacity: 0, x: -10 }}
   424→              transition={{ duration: 0.15 }}
   425→              className="space-y-6"
   426→            >
   427→              {/* General Settings */}
   428→              {currentTab === 'general' && (
   429→                <>
   430→                  <AccountSettings />
   431→                  <SiteWideSettings />
   432→                  <DashboardSettingsSection onOpenPresetManager={() => setShowPresetManager(true)} />
   433→                  <div className="bento-card p-6">
   434→                    <WidgetSettingsSection />
   435→                  </div>
   436→                </>
   437→              )}
   438→
   439→              {/* Projects Settings */}
   440→              {currentTab === 'projects' && <ProjectSettings />}
   441→
   442→              {/* Time Tracking Settings */}
   443→              {currentTab === 'time' && (
   444→                <>
   445→                  <div className="bento-card p-6">
   446→                    <TimeTrackingPanelSettings />
   447→                  </div>
   448→                  <div className="bento-card p-6">
   449→                    <AutoTrackingSettings />
   450→                  </div>
   451→                </>
   452→              )}
   453→
   454→              {/* Task Settings */}
   455→              {currentTab === 'tasks' && (
   456→                <TaskManagementSettings />
   457→              )}
   458→
   459→              {/* Notes & Calendar Settings */}
   460→              {currentTab === 'notes' && (
   461→                <>
   462→                  <div className="bento-card p-6">
   463→                    <DailyNotesSettings />
   464→                  </div>
   465→                  <div className="bento-card p-6">
   466→                    <TemplateSettings />
   467→                  </div>
   468→                  <div className="bento-card p-6">
   469→                    <ExportSettings />
   470→                  </div>
   471→
   472→                  <CalendarImportExportSection
   473→                    isExporting={isExportingCalendar}
   474→                    isImporting={isImportingCalendar}
   475→                    onExport={handleExportCalendar}
   476→                    onImport={handleICSFileSelect}
   477→                  />
   478→
   479→                  <CalendarNotificationsSection
   480→                    notificationPermission={notificationPermission}
   481→                    requestingPermission={requestingPermission}
   482→                    onRequestPermission={handleRequestNotificationPermission}
   483→                  />
   484→                </>
   485→              )}
   486→
   487→              {/* Backup & Data Settings */}
   488→              {currentTab === 'backup' && (
   489→                <>
   490→                  {/* Privacy Notice */}
   491→                  <div className="p-4 rounded-lg bg-status-success-bg dark:bg-status-success-bg-dark border border-status-success-border dark:border-status-success-border-dark">
   492→                    <p className="text-sm text-status-success-text dark:text-status-success-text-dark">
   493→                      <strong>🔒 100% Private:</strong> All data stored locally in your browser using IndexedDB (50GB+ capacity).
   494→                      No cloud dependencies, no tracking, no third-party services.
   495→                    </p>
   496→                  </div>
   497→
   498→                  {/* New Browser Warning */}
   499→                  {showNewBrowserWarning && (
   500→                    <motion.div
   501→                      initial={{ opacity: 0, y: -10 }}
   502→                      animate={{ opacity: 1, y: 0 }}
   503→                      className="p-6 rounded-lg bg-status-warning-bg dark:bg-status-warning-bg-dark border-2 border-status-warning-border dark:border-status-warning-border-dark"
   504→                    >
   505→                      <div className="flex items-start gap-4">
   506→                        <span className="text-3xl flex-shrink-0">⚠️</span>
   507→                        <div className="flex-1">
   508→                          <h3 className="text-xl font-bold text-status-warning-text dark:text-status-warning-text-dark mb-2">
   509→                            First Time in This Browser?
   510→                          </h3>
   511→                          <p className="text-sm text-status-warning-text dark:text-status-warning-text-dark mb-3">
   512→                            Your data is stored locally in each browser. Export from your other browser and import here.
   513→                          </p>
   514→                          <div className="flex flex-wrap gap-2">
   515→                            <button
   516→                              onClick={() => setShowNewBrowserWarning(false)}
   517→                              className="px-4 py-2 bg-status-warning text-white rounded-lg font-medium transition-colors"
   518→                            >
   519→                              Got It
   520→                            </button>
   521→                            <button
   522→                              onClick={() => {
   523→                                setShowNewBrowserWarning(false);
   524→                                localStorage.setItem('new-browser-warning-dismissed', 'true');
   525→                              }}
   526→                              className="px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary rounded-lg font-medium transition-colors border border-border-light dark:border-border-dark"
   527→                            >
   528→                              Don't Show Again
   529→                            </button>
   530→                          </div>
   531→                        </div>
   532→                      </div>
   533→                    </motion.div>
   534→                  )}
   535→
   536→                  <QuickActionsSection
   537→                    timeSinceLastBackup={timeSinceLastBackup}
   538→                    isExporting={isExporting}
   539→                    isImporting={isImporting}
   540→                    onExport={() => handleExport(preferences.compressionEnabled)}
   541→                    onFileSelect={handleFileSelect}
   542→                  />
   543→
   544→                  <BackupHistorySection backupHistory={backupHistory} />
   545→
   546→                  <BackupOptionsSection
   547→                    preferences={preferences}
   548→                    onRefresh={loadAllData}
   549→                    onMessage={setMessage}
   550→                  />
   551→
   552→                  <AutoSaveSettings
   553→                    onMessage={setMessage}
   554→                    onRefresh={loadAllData}
   555→                  />
   556→
   557→                  <div className="bento-card p-6">
   558→                    <BackupSettings />
   559→                  </div>
   560→
   561→                  <div className="bento-card p-6">
   562→                    <ImportData />
   563→                  </div>
   564→                </>
   565→              )}
   566→
