      </div>

      {/* Action Bar - scrollable on narrow screens */}
      <div className="flex items-center gap-3 mb-3 flex-shrink-0 overflow-x-auto pb-1">
      {/* Search */}
      <div className="min-w-[200px] max-w-xs flex-shrink-0">
